SELECT sample_name, sequencing_platform
FROM sequencing_runs
ORDER BY total_reads DESC;

SELECT run_id
FROM sequencing_runs
ORDER BY run_id;

SELECT run_id, total_reads
FROM sequencing_runs
ORDER BY total_reads DESC;

SELECT sequencing_platform, AVG(total_reads) AS average_reads
FROM sequencing_runs
GROUP BY sequencing_platform;
